insert into public.aira_settings (key, value, updated_at) values
('question_bank', $${"version": "v11.0-package-template-linking", "assistantName": "Aira", "positioning": "AI Website Consultant", "intro": ["Hai 👋 Saya <strong>Aira</strong>, AI Website Consultant RH.", "Saya akan bantu cadangkan pakej rasmi <strong>RH Starter</strong>, <strong>RH Growth</strong> atau <strong>RH Ecosystem</strong> mengikut keperluan bisnes anda."], "steps": [{"key": "business_type", "question": "Apakah kategori perniagaan yang ingin anda bina website?", "type": "choice", "required": true, "options": ["Servis Aircond", "Plumbing", "Elektrik", "Cleaning Service", "Pest Control", "Bengkel Kereta", "Spa & Beauty", "Personal Brand", "NGO / Persatuan", "Servis Kecil Lain", "Homestay", "Kereta Sewa", "Kedai Makan / Restoran", "Butik / Fashion", "Produk Online", "Kontraktor & Renovasi", "Interior Design", "Wedding Planner", "Event Management", "Pusat Tuisyen / Kelas", "Company Profile", "Konsultan / Consultant", "Klinik / Profesional Kesihatan", "Dental Clinic", "Law Firm", "Accounting Firm", "Hartanah / Property Agent", "Training Centre", "Security Service", "Engineering Firm", "Hotel & Resort", "Developer Project", "Medical Group", "Manufacturing", "Franchise Business", "Multi-Branch Business", "Creative Agency", "Travel Agency", "E-commerce Katalog Besar", "Custom System / Portal"]}, {"key": "objective", "question": "Apakah matlamat utama website ini?", "type": "choice", "required": true, "options": ["Dapatkan lebih banyak pertanyaan pelanggan", "Paparkan servis & portfolio", "Tempahan / booking enquiry", "Company profile yang lebih dipercayai", "Jual produk / katalog online", "Landing page untuk iklan", "Premium branding & conversion", "Website custom mengikut scope"]}, {"key": "has_website", "question": "Adakah anda sudah mempunyai website sekarang?", "type": "choice", "required": false, "options": ["Belum ada website", "Ada, tetapi mahu upgrade", "Ada domain sahaja", "Belum pasti"]}, {"key": "has_domain", "question": "Adakah anda sudah mempunyai domain sendiri?", "type": "choice", "required": false, "options": ["Ya, sudah ada domain", "Belum ada domain", "Perlu bantuan beli domain", "Belum pasti"]}, {"key": "content_ready", "question": "Bahan website sudah tersedia?", "type": "choice", "required": false, "options": ["Logo & gambar sudah ada", "Ada sebahagian bahan", "Belum ada bahan", "Perlu bantuan susun content"]}, {"key": "industry_detail", "question": "Maklumat tambahan yang penting untuk kategori bisnes anda?", "type": "choice", "required": false, "conditional": true, "conditions": {"Servis Aircond": ["Servis rumah", "Servis pejabat", "Ada kawasan liputan tertentu", "Perlu jadual servis / booking"], "Plumbing": ["Servis kecemasan", "Servis rumah", "Servis bangunan", "Perlu borang quotation"], "Elektrik": ["Wiring rumah", "Wiring komersial", "Maintenance berkala", "Perlu paparan lesen / sijil"], "Cleaning Service": ["Rumah", "Pejabat", "Post-renovation", "Recurring service"], "Homestay": ["1 unit homestay", "2–5 unit homestay", "Lebih 5 unit", "Perlu galeri & kemudahan"], "Kereta Sewa": ["1–5 kenderaan", "6–20 kenderaan", "Lebih 20 kenderaan", "Perlu senarai harga & booking"], "Kedai Makan / Restoran": ["Menu harian", "Catering", "Tempahan WhatsApp", "Lokasi Google Maps"], "Butik / Fashion": ["Koleksi produk", "Katalog WhatsApp", "Promosi seasonal", "Perlu lookbook"], "Produk Online": ["1 produk utama", "Katalog banyak produk", "Perlu testimoni", "Order melalui WhatsApp"], "Kontraktor & Renovasi": ["Ada portfolio projek", "Belum ada portfolio", "Perlu quotation form", "Perlu paparan servis lengkap"], "Company Profile": ["Syarikat baru", "Syarikat sedia ada", "Perlu profil korporat", "Perlu paparan team / projek"], "Klinik / Profesional Kesihatan": ["Klinik umum", "Specialist", "Perlu appointment enquiry", "Perlu servis rawatan"], "Hartanah / Property Agent": ["Listing hartanah", "Lead buyer / tenant", "Project showcase", "Perlu borang enquiry"], "Hotel & Resort": ["Room showcase", "Booking enquiry", "Facili